-- Base de leads demo para o Mangaba AI
-- 100 contatos brasileiros fictícios prontos para campanhas de reativação / promoção

CREATE TABLE IF NOT EXISTS clientes (
  id          SERIAL PRIMARY KEY,
  nome        VARCHAR(120) NOT NULL,
  telefone    VARCHAR(20)  NOT NULL,
  email       VARCHAR(120),
  cidade      VARCHAR(80),
  estado      CHAR(2),
  segmento    VARCHAR(60),
  plano       VARCHAR(40),
  ticket_medio NUMERIC(10,2),
  dias_inativo INTEGER DEFAULT 0,
  ultima_compra DATE,
  criado_em   TIMESTAMP DEFAULT NOW()
);


-- View útil para filtrar leads inativos (bons para reativação)
CREATE OR REPLACE VIEW leads_inativos AS
  SELECT * FROM clientes WHERE dias_inativo >= 30 ORDER BY dias_inativo DESC;

-- View para leads de alto valor (bons para upsell)
CREATE OR REPLACE VIEW leads_alto_valor AS
  SELECT * FROM clientes WHERE ticket_medio >= 400 ORDER BY ticket_medio DESC;
